SELECT attributes.attribute_name, classes.class_name
FROM attributes
INNER JOIN classes ON attributes.class_id = classes.class_id;

SELECT 
    (SELECT COUNT(*) FROM classes WHERE status = 'active') AS active_classes,
    (SELECT COUNT(*) FROM attributes WHERE status = 'active') AS active_attributes;

SELECT 
    (SELECT COUNT(class_id) FROM classes) AS number_of_classes,
    (SELECT COUNT(attribute_id) FROM attributes) AS number_of_attributes;

SELECT value_id, attribute_id, value,
       RANK() OVER (PARTITION BY attribute_id ORDER BY value ASC) as rank_within_attribute
FROM data_values;

SELECT c.class_name
FROM classes c
WHERE c.maximum_cardinality > (SELECT AVG(maximum_cardinality) FROM classes);

SELECT data_type_name, COUNT(data_type_name) AS data_type_count
FROM value_types
GROUP BY data_type_name;

SELECT
    (SELECT COUNT(*) FROM classes WHERE status = 'active') AS active_classes,
    (SELECT COUNT(*) FROM attributes WHERE status = 'active' AND class_id IN (SELECT class_id FROM classes WHERE status = 'active')) AS active_attributes;

SELECT c.*, a.*
FROM classes c
LEFT JOIN attributes a ON c.class_id = a.class_id;

SELECT a.attribute_id, a.attribute_name, u.unit_name
FROM attributes a
JOIN units_of_measure u ON a.unit_of_measure_type = u.unit_id;

SELECT attributes.attribute_id, attributes.attribute_name, data_values.value, data_values.value_date
FROM attributes
JOIN data_values ON attributes.attribute_id = data_values.attribute_id;

SELECT class_name
FROM classes
WHERE minimum_cardinality >= 5 AND maximum_cardinality <= 10;
